import React, { useState, useEffect, useRef } from 'react';

const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    positive: '#10b981',
    negative: '#f43f5e',
    blue: '#38bdf8',
    yellow: '#fbbf24',
    pink: '#f472b6',
    green: '#a3e635',
    orange: '#fb923c',
  },
  font: "'JetBrains Mono', monospace",
};

const examples = [
  {
    name: 'Simple Line',
    X: [[1, 1], [1, 2], [1, 3]],
    y: [1, 2, 3],
    alpha: 0.1,
    t0Range: [-1, 2],
    t1Range: [-0.5, 2],
  },
  {
    name: 'With Intercept',
    X: [[1, 1], [1, 2], [1, 3], [1, 4]],
    y: [3, 5, 7, 9],
    alpha: 0.1,
    t0Range: [-1, 3],
    t1Range: [0, 3],
  },
  {
    name: 'Scattered',
    X: [[1, 0], [1, 1], [1, 2], [1, 3]],
    y: [1, 2.5, 2, 4],
    alpha: 0.1,
    t0Range: [-1, 3],
    t1Range: [-0.5, 2],
  },
];

const stepInfo = [
  {
    title: 'Explore the Loss Landscape',
    desc: 'Drag the green ball on the contour plot to explore! Darker = lower loss. Watch how the fit line changes. Find the minimum, then click Start.',
    color: theme.colors.primary,
  },
  {
    title: 'Step 1: Make Predictions',
    desc: 'Multiply data X by current weights theta. Each prediction is theta0 + theta1 * x.',
    color: theme.colors.blue,
  },
  {
    title: 'Step 2: Calculate Errors',
    desc: 'Error = prediction minus actual (y). Loss = mean squared error. The higher up on the landscape, the larger the loss.',
    color: theme.colors.negative,
  },
  {
    title: 'Step 3: Compute the Gradient',
    desc: 'The gradient (orange arrow) points uphill. We move opposite (green dashed) to descend toward lower loss.',
    color: theme.colors.orange,
  },
  {
    title: 'Step 4: First Update',
    desc: 'Move theta opposite to gradient, scaled by alpha. Watch the ball take its first step downhill!',
    color: theme.colors.green,
  },
  {
    title: 'Step 5: Second Update',
    desc: 'One more manual step. Notice how the gradient changes direction as we move through the landscape.',
    color: theme.colors.green,
  },
  {
    title: 'Converging to Minimum',
    desc: 'Now watch gradient descent run to completion. The path traces our descent through the loss landscape.',
    color: theme.colors.primary,
  },
];

export default function App() {
  const [exampleIdx, setExampleIdx] = useState(0);
  const [step, setStep] = useState(0);
  const [playing, setPlaying] = useState(false);
  const [iteration, setIteration] = useState(0);
  const [theta, setTheta] = useState([0, 0]);
  const [predictions, setPredictions] = useState([]);
  const [errors, setErrors] = useState([]);
  const [gradient, setGradient] = useState([0, 0]);
  const [iterating, setIterating] = useState(false);
  const [path, setPath] = useState([[0, 0]]);
  const [dragging, setDragging] = useState(false);
  const scatterRef = useRef(null);
  const contourRef = useRef(null);
  const iterRef = useRef(null);

  const totalSteps = 6;
  const ex = examples[exampleIdx];
  const size = 200;
  const padding = 28;
  const plotSize = size - 2 * padding;

  const computePredictions = (th, data) => data.X.map(row => row[0] * th[0] + row[1] * th[1]);
  const computeErrors = (preds, data) => preds.map((p, i) => p - data.y[i]);
  const computeGradient = (errs, data) => {
    const len = data.X.length;
    const g0 = errs.reduce((sum, e, i) => sum + e * data.X[i][0], 0) / len;
    const g1 = errs.reduce((sum, e, i) => sum + e * data.X[i][1], 0) / len;
    return [g0, g1];
  };
  const computeLoss = (th, data) => {
    const preds = computePredictions(th, data);
    const errs = computeErrors(preds, data);
    return errs.reduce((sum, e) => sum + e * e, 0) / data.X.length;
  };

  const reset = () => {
    setStep(0);
    setPlaying(false);
    setIteration(0);
    setTheta([0, 0]);
    setPredictions([]);
    setErrors([]);
    setGradient([0, 0]);
    setIterating(false);
    setPath([[0, 0]]);
    if (iterRef.current) clearInterval(iterRef.current);
  };

  const doOneIteration = (currentTheta, currentPath) => {
    const preds = computePredictions(currentTheta, ex);
    const errs = computeErrors(preds, ex);
    const grad = computeGradient(errs, ex);
    const newTheta = [
      currentTheta[0] - ex.alpha * grad[0],
      currentTheta[1] - ex.alpha * grad[1],
    ];
    const newPath = [...currentPath, newTheta];
    return { newTheta, newPath, grad };
  };

  const next = () => {
    if (step < totalSteps) {
      const nextStep = step + 1;
      setStep(nextStep);

      if (nextStep === 1) {
        setPredictions(computePredictions(theta, ex));
      } else if (nextStep === 2) {
        const preds = computePredictions(theta, ex);
        setPredictions(preds);
        setErrors(computeErrors(preds, ex));
      } else if (nextStep === 3) {
        const preds = computePredictions(theta, ex);
        const errs = computeErrors(preds, ex);
        setGradient(computeGradient(errs, ex));
      } else if (nextStep === 4) {
        const { newTheta, newPath, grad } = doOneIteration(theta, path);
        setTheta(newTheta);
        setPath(newPath);
        setGradient(grad);
        setIteration(1);
      } else if (nextStep === 5) {
        const { newTheta, newPath, grad } = doOneIteration(theta, path);
        setTheta(newTheta);
        setPath(newPath);
        setGradient(grad);
        setIteration(2);
      } else if (nextStep === 6) {
        setIterating(true);
      }
    }
  };

  const prev = () => step > 0 && setStep(step - 1);

  const auto = async () => {
    setPlaying(true);
    let currentTheta = [...theta];
    let currentGradient = [...gradient];
    let currentPath = [...path];
    let currentIter = iteration;

    for (let s = step; s <= totalSteps; s++) {
      setStep(s);
      if (s === 1) {
        setPredictions(computePredictions(currentTheta, ex));
      } else if (s === 2) {
        const preds = computePredictions(currentTheta, ex);
        setPredictions(preds);
        setErrors(computeErrors(preds, ex));
      } else if (s === 3) {
        const preds = computePredictions(currentTheta, ex);
        const errs = computeErrors(preds, ex);
        currentGradient = computeGradient(errs, ex);
        setGradient(currentGradient);
      } else if (s === 4) {
        const result = doOneIteration(currentTheta, currentPath);
        currentTheta = result.newTheta;
        currentPath = result.newPath;
        currentGradient = result.grad;
        setTheta(currentTheta);
        setPath(currentPath);
        setGradient(currentGradient);
        currentIter = 1;
        setIteration(1);
      } else if (s === 5) {
        const result = doOneIteration(currentTheta, currentPath);
        currentTheta = result.newTheta;
        currentPath = result.newPath;
        currentGradient = result.grad;
        setTheta(currentTheta);
        setPath(currentPath);
        setGradient(currentGradient);
        currentIter = 2;
        setIteration(2);
      } else if (s === 6) {
        setIterating(true);
      }
      await new Promise(r => setTimeout(r, 1000));
    }
    setPlaying(false);
  };

  // Auto iteration loop
  useEffect(() => {
    if (!iterating || iteration >= 50) {
      if (iterRef.current) clearInterval(iterRef.current);
      return;
    }

    iterRef.current = setInterval(() => {
      setTheta(prevTheta => {
        const preds = computePredictions(prevTheta, ex);
        const errs = computeErrors(preds, ex);
        const grad = computeGradient(errs, ex);
        const newTheta = [
          prevTheta[0] - ex.alpha * grad[0],
          prevTheta[1] - ex.alpha * grad[1],
        ];
        setPath(prev => [...prev, newTheta]);
        setGradient(grad);
        return newTheta;
      });
      setIteration(prev => {
        if (prev >= 49) clearInterval(iterRef.current);
        return prev + 1;
      });
    }, 80);

    return () => { if (iterRef.current) clearInterval(iterRef.current); };
  }, [iterating, exampleIdx]);

  // Mouse handlers for dragging
  const getMouseTheta = (e) => {
    const canvas = contourRef.current;
    const rect = canvas.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    const [t0Min, t0Max] = ex.t0Range;
    const [t1Min, t1Max] = ex.t1Range;

    const t0 = t0Min + ((x - padding) / plotSize) * (t0Max - t0Min);
    const t1 = t1Max - ((y - padding) / plotSize) * (t1Max - t1Min);

    return [
      Math.max(t0Min, Math.min(t0Max, t0)),
      Math.max(t1Min, Math.min(t1Max, t1)),
    ];
  };

  const handleMouseDown = (e) => {
    if (step > 0) return;
    setDragging(true);
    const newTheta = getMouseTheta(e);
    setTheta(newTheta);
    setPath([newTheta]);
  };

  const handleMouseMove = (e) => {
    if (!dragging || step > 0) return;
    const newTheta = getMouseTheta(e);
    setTheta(newTheta);
    setPath([newTheta]);
  };

  const handleMouseUp = () => {
    setDragging(false);
  };

  // Scatter plot
  useEffect(() => {
    const canvas = scatterRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');

    ctx.fillStyle = theme.colors.surface;
    ctx.fillRect(0, 0, size, size);

    const xVals = ex.X.map(row => row[1]);
    const yVals = ex.y;
    const xMin = Math.min(...xVals) - 0.5;
    const xMax = Math.max(...xVals) + 0.5;
    const yMin = Math.min(...yVals, 0) - 0.5;
    const yMax = Math.max(...yVals) + 1.5;

    const scaleX = (x) => padding + ((x - xMin) / (xMax - xMin)) * plotSize;
    const scaleY = (y) => size - padding - ((y - yMin) / (yMax - yMin)) * plotSize;

    // Grid
    ctx.strokeStyle = theme.colors.border;
    ctx.lineWidth = 1;
    for (let i = 0; i <= 4; i++) {
      const x = padding + (i / 4) * plotSize;
      const y = padding + (i / 4) * plotSize;
      ctx.beginPath(); ctx.moveTo(x, padding); ctx.lineTo(x, size - padding); ctx.stroke();
      ctx.beginPath(); ctx.moveTo(padding, y); ctx.lineTo(size - padding, y); ctx.stroke();
    }

    ctx.fillStyle = theme.colors.textMuted;
    ctx.font = '9px JetBrains Mono, monospace';
    ctx.textAlign = 'center';
    ctx.fillText('x', size - 12, size - padding + 4);
    ctx.fillText('y', padding - 4, 16);

    // Regression line (always show when exploring or after step 1)
    const showLine = step >= 1 || step === 0;
    if (showLine) {
      ctx.strokeStyle = step >= 4 ? theme.colors.green : theme.colors.blue;
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(scaleX(xMin), scaleY(theta[0] + theta[1] * xMin));
      ctx.lineTo(scaleX(xMax), scaleY(theta[0] + theta[1] * xMax));
      ctx.stroke();
    }

    // Error lines
    if (step >= 2 && step < 6 && errors.length > 0) {
      ctx.strokeStyle = theme.colors.negative;
      ctx.lineWidth = 2;
      ctx.setLineDash([4, 4]);
      ex.X.forEach((row, i) => {
        const x = row[1];
        const pred = theta[0] + theta[1] * x;
        ctx.beginPath();
        ctx.moveTo(scaleX(x), scaleY(ex.y[i]));
        ctx.lineTo(scaleX(x), scaleY(pred));
        ctx.stroke();
      });
      ctx.setLineDash([]);
    }

    // Data points
    ex.X.forEach((row, i) => {
      ctx.fillStyle = theme.colors.pink;
      ctx.beginPath();
      ctx.arc(scaleX(row[1]), scaleY(ex.y[i]), 5, 0, Math.PI * 2);
      ctx.fill();
    });

    // Predictions
    if (step >= 1) {
      ex.X.forEach((row) => {
        ctx.fillStyle = theme.colors.blue;
        ctx.beginPath();
        ctx.arc(scaleX(row[1]), scaleY(theta[0] + theta[1] * row[1]), 3, 0, Math.PI * 2);
        ctx.fill();
      });
    }
  }, [step, theta, errors, exampleIdx, iteration]);

  // Contour plot
  useEffect(() => {
    const canvas = contourRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');

    ctx.fillStyle = theme.colors.surface;
    ctx.fillRect(0, 0, size, size);

    const [t0Min, t0Max] = ex.t0Range;
    const [t1Min, t1Max] = ex.t1Range;

    const scaleX = (t0) => padding + ((t0 - t0Min) / (t0Max - t0Min)) * plotSize;
    const scaleY = (t1) => size - padding - ((t1 - t1Min) / (t1Max - t1Min)) * plotSize;

    // Compute loss grid
    const resolution = 50;
    const lossGrid = [];
    let minLoss = Infinity, maxLoss = 0;

    for (let i = 0; i < resolution; i++) {
      lossGrid[i] = [];
      for (let j = 0; j < resolution; j++) {
        const t0 = t0Min + (i / (resolution - 1)) * (t0Max - t0Min);
        const t1 = t1Min + (j / (resolution - 1)) * (t1Max - t1Min);
        const loss = computeLoss([t0, t1], ex);
        lossGrid[i][j] = loss;
        minLoss = Math.min(minLoss, loss);
        maxLoss = Math.max(maxLoss, loss);
      }
    }

    // Draw heatmap
    const cellW = plotSize / resolution;
    const cellH = plotSize / resolution;

    for (let i = 0; i < resolution; i++) {
      for (let j = 0; j < resolution; j++) {
        const loss = lossGrid[i][j];
        const normalized = Math.pow((loss - minLoss) / (maxLoss - minLoss + 0.001), 0.5);
        const hue = 260 - normalized * 60;
        const lightness = 15 + (1 - normalized) * 25;
        ctx.fillStyle = `hsl(${hue}, 70%, ${lightness}%)`;
        ctx.fillRect(
          padding + i * cellW,
          size - padding - (j + 1) * cellH,
          cellW + 1,
          cellH + 1
        );
      }
    }

    // Contour lines
    ctx.strokeStyle = 'rgba(255,255,255,0.15)';
    ctx.lineWidth = 1;
    const contourLevels = [0.1, 0.5, 1, 2, 4, 8].filter(l => l >= minLoss && l <= maxLoss);
    contourLevels.forEach(level => {
      for (let i = 0; i < resolution - 1; i++) {
        for (let j = 0; j < resolution - 1; j++) {
          const corners = [lossGrid[i][j], lossGrid[i+1][j], lossGrid[i+1][j+1], lossGrid[i][j+1]];
          const above = corners.map(c => c > level);
          if (above.some(a => a) && above.some(a => !a)) {
            const t0 = t0Min + ((i + 0.5) / (resolution - 1)) * (t0Max - t0Min);
            const t1 = t1Min + ((j + 0.5) / (resolution - 1)) * (t1Max - t1Min);
            ctx.beginPath();
            ctx.arc(scaleX(t0), scaleY(t1), 1, 0, Math.PI * 2);
            ctx.stroke();
          }
        }
      }
    });

    // Axes
    ctx.fillStyle = theme.colors.textMuted;
    ctx.font = '9px JetBrains Mono, monospace';
    ctx.textAlign = 'center';
    ctx.fillText('theta0', size / 2, size - 8);
    ctx.save();
    ctx.translate(10, size / 2);
    ctx.rotate(-Math.PI / 2);
    ctx.fillText('theta1', 0, 0);
    ctx.restore();

    // Path
    if (path.length > 1) {
      ctx.strokeStyle = theme.colors.green;
      ctx.lineWidth = 2;
      ctx.beginPath();
      path.forEach((p, i) => {
        const x = scaleX(p[0]);
        const y = scaleY(p[1]);
        if (i === 0) ctx.moveTo(x, y);
        else ctx.lineTo(x, y);
      });
      ctx.stroke();

      path.forEach((p, i) => {
        if (i < path.length - 1 && i % 5 !== 0 && i !== 0) return;
        ctx.fillStyle = i === path.length - 1 ? theme.colors.green : 'rgba(163, 230, 53, 0.5)';
        ctx.beginPath();
        ctx.arc(scaleX(p[0]), scaleY(p[1]), i === path.length - 1 ? 6 : 3, 0, Math.PI * 2);
        ctx.fill();
      });
    }

    // Current position
    const cx = scaleX(theta[0]);
    const cy = scaleY(theta[1]);

    ctx.fillStyle = theme.colors.green + '40';
    ctx.beginPath();
    ctx.arc(cx, cy, 14, 0, Math.PI * 2);
    ctx.fill();

    ctx.fillStyle = theme.colors.green;
    ctx.beginPath();
    ctx.arc(cx, cy, 7, 0, Math.PI * 2);
    ctx.fill();

    // Drag hint at step 0
    if (step === 0) {
      ctx.fillStyle = theme.colors.text;
      ctx.font = '8px JetBrains Mono, monospace';
      ctx.textAlign = 'center';
      ctx.fillText('drag me!', cx, cy - 18);
    }

    // Gradient arrow (steps 3, 4, 5)
    if ((step === 3 || step === 4 || step === 5) && (gradient[0] !== 0 || gradient[1] !== 0)) {
      const gradMag = Math.sqrt(gradient[0] ** 2 + gradient[1] ** 2);
      const scale = 35 / Math.max(gradMag, 0.5);
      const gx = gradient[0] * scale;
      const gy = -gradient[1] * scale;

      ctx.strokeStyle = theme.colors.orange;
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.moveTo(cx, cy);
      ctx.lineTo(cx + gx, cy + gy);
      ctx.stroke();

      const angle = Math.atan2(gy, gx);
      ctx.beginPath();
      ctx.moveTo(cx + gx, cy + gy);
      ctx.lineTo(cx + gx - 8 * Math.cos(angle - 0.4), cy + gy - 8 * Math.sin(angle - 0.4));
      ctx.lineTo(cx + gx - 8 * Math.cos(angle + 0.4), cy + gy - 8 * Math.sin(angle + 0.4));
      ctx.closePath();
      ctx.fillStyle = theme.colors.orange;
      ctx.fill();

      if (step === 3) {
        ctx.strokeStyle = theme.colors.green;
        ctx.lineWidth = 2;
        ctx.setLineDash([4, 4]);
        ctx.beginPath();
        ctx.moveTo(cx, cy);
        ctx.lineTo(cx - gx * 0.5, cy - gy * 0.5);
        ctx.stroke();
        ctx.setLineDash([]);
      }
    }

    // Start marker
    if (path.length > 0 && step > 0) {
      const startX = scaleX(path[0][0]);
      const startY = scaleY(path[0][1]);
      ctx.strokeStyle = theme.colors.textMuted;
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.arc(startX, startY, 8, 0, Math.PI * 2);
      ctx.stroke();
      ctx.fillStyle = theme.colors.textMuted;
      ctx.font = '8px JetBrains Mono, monospace';
      ctx.fillText('start', startX, startY - 12);
    }

  }, [step, theta, path, gradient, exampleIdx, iteration, dragging]);

  const formatNum = (n) => n.toFixed(3);
  const currentLoss = computeLoss(theta, ex);

  return (
    <div style={{
      background: theme.colors.background,
      padding: '16px',
      fontFamily: theme.font,
      color: theme.colors.text,
      minHeight: '100vh',
      boxSizing: 'border-box',
    }}>
      {/* Header */}
      <div style={{ textAlign: 'center', marginBottom: '12px' }}>
        <div style={{ fontSize: '18px', fontWeight: '700' }}>
          Gradient Descent for Linear Regression
        </div>
        <div style={{ fontSize: '11px', color: theme.colors.textSecondary }}>
          {step === 0 ? 'Drag the ball to explore, then click Start' : 'Watch the descent through the loss landscape'}
        </div>
      </div>

      {/* Example Tabs */}
      <div style={{ display: 'flex', gap: '6px', justifyContent: 'center', marginBottom: '12px' }}>
        {examples.map((e, idx) => (
          <button
            key={idx}
            onClick={() => { setExampleIdx(idx); reset(); }}
            style={{
              padding: '6px 12px',
              background: exampleIdx === idx ? theme.colors.primary : theme.colors.surface,
              border: 'none',
              borderRadius: '6px',
              color: exampleIdx === idx ? '#fff' : theme.colors.textSecondary,
              fontFamily: theme.font,
              fontSize: '11px',
              cursor: 'pointer',
            }}
          >
            {e.name}
          </button>
        ))}
      </div>

      {/* Dual Visualization */}
      <div style={{ 
        display: 'flex', 
        gap: '12px', 
        justifyContent: 'center', 
        marginBottom: '12px',
        flexWrap: 'wrap',
      }}>
        <div style={{ textAlign: 'center' }}>
          <div style={{ fontSize: '10px', color: theme.colors.textMuted, marginBottom: '4px' }}>
            Data + Fit Line
          </div>
          <canvas
            ref={scatterRef}
            width={size}
            height={size}
            style={{ borderRadius: '8px', border: '1px solid ' + theme.colors.border }}
          />
        </div>

        <div style={{ textAlign: 'center' }}>
          <div style={{ fontSize: '10px', color: theme.colors.textMuted, marginBottom: '4px' }}>
            Loss Landscape (darker = lower)
          </div>
          <canvas
            ref={contourRef}
            width={size}
            height={size}
            style={{ 
              borderRadius: '8px', 
              border: '1px solid ' + (step === 0 ? theme.colors.primary : theme.colors.border),
              cursor: step === 0 ? 'grab' : 'default',
            }}
            onMouseDown={handleMouseDown}
            onMouseMove={handleMouseMove}
            onMouseUp={handleMouseUp}
            onMouseLeave={handleMouseUp}
          />
        </div>
      </div>

      {/* Stats Display */}
      <div style={{
        display: 'flex',
        justifyContent: 'center',
        gap: '10px',
        marginBottom: '12px',
        flexWrap: 'wrap',
      }}>
        <div style={{
          padding: '6px 10px',
          background: theme.colors.surface,
          borderRadius: '6px',
          border: '1px solid ' + (step >= 4 ? theme.colors.green : theme.colors.border),
        }}>
          <span style={{ fontSize: '9px', color: theme.colors.textMuted }}>theta0</span>
          <div style={{ fontSize: '14px', fontWeight: '600', color: theme.colors.green }}>
            {formatNum(theta[0])}
          </div>
        </div>
        <div style={{
          padding: '6px 10px',
          background: theme.colors.surface,
          borderRadius: '6px',
          border: '1px solid ' + (step >= 4 ? theme.colors.green : theme.colors.border),
        }}>
          <span style={{ fontSize: '9px', color: theme.colors.textMuted }}>theta1</span>
          <div style={{ fontSize: '14px', fontWeight: '600', color: theme.colors.green }}>
            {formatNum(theta[1])}
          </div>
        </div>
        <div style={{
          padding: '6px 10px',
          background: theme.colors.surface,
          borderRadius: '6px',
          border: '1px solid ' + theme.colors.yellow,
        }}>
          <span style={{ fontSize: '9px', color: theme.colors.textMuted }}>loss</span>
          <div style={{ fontSize: '14px', fontWeight: '600', color: theme.colors.yellow }}>
            {formatNum(currentLoss)}
          </div>
        </div>
        {iteration > 0 && (
          <div style={{
            padding: '6px 10px',
            background: theme.colors.surface,
            borderRadius: '6px',
          }}>
            <span style={{ fontSize: '9px', color: theme.colors.textMuted }}>iter</span>
            <div style={{ fontSize: '14px', fontWeight: '600', color: theme.colors.primary }}>
              {iteration}
            </div>
          </div>
        )}
      </div>

      {/* Step Explanation */}
      <div style={{
        padding: '10px 12px',
        background: theme.colors.surface,
        borderRadius: '8px',
        borderLeft: '3px solid ' + stepInfo[step].color,
        marginBottom: '12px',
      }}>
        <div style={{ fontSize: '12px', fontWeight: '600', color: theme.colors.text }}>
          {stepInfo[step].title}
        </div>
        <div style={{ fontSize: '11px', color: theme.colors.textSecondary, lineHeight: 1.5 }}>
          {stepInfo[step].desc}
        </div>
      </div>

      {/* Step Dots */}
      <div style={{ display: 'flex', gap: '4px', justifyContent: 'center', marginBottom: '12px' }}>
        {Array.from({ length: totalSteps + 1 }).map((_, i) => (
          <div
            key={i}
            style={{
              width: i === step ? '20px' : '8px',
              height: '8px',
              borderRadius: '4px',
              background: i <= step ? theme.colors.primary : theme.colors.border,
              transition: 'all 0.3s',
            }}
          />
        ))}
      </div>

      {/* Controls */}
      <div style={{ display: 'flex', gap: '8px', alignItems: 'center', marginBottom: '12px' }}>
        <button
          onClick={prev}
          disabled={step <= 0 || playing}
          style={{
            padding: '8px 12px',
            background: step <= 0 ? theme.colors.border : theme.colors.surface,
            border: 'none',
            borderRadius: '6px',
            color: step <= 0 ? theme.colors.textMuted : theme.colors.text,
            fontFamily: theme.font,
            fontSize: '14px',
            cursor: step <= 0 ? 'not-allowed' : 'pointer',
          }}
        >
          {'<'}
        </button>
        <button
          onClick={next}
          disabled={step >= totalSteps || playing}
          style={{
            flex: 1,
            padding: '10px 16px',
            background: theme.colors.primary,
            border: 'none',
            borderRadius: '6px',
            color: '#fff',
            fontFamily: theme.font,
            fontSize: '12px',
            fontWeight: '600',
            cursor: step >= totalSteps ? 'not-allowed' : 'pointer',
            opacity: step >= totalSteps ? 0.5 : 1,
          }}
        >
          {step === 0 ? 'Start' : step < totalSteps ? 'Next Step' : 'Complete!'}
        </button>
        <button
          onClick={auto}
          disabled={playing || step >= totalSteps}
          style={{
            padding: '8px 12px',
            background: playing ? theme.colors.border : theme.colors.surface,
            border: 'none',
            borderRadius: '6px',
            color: playing ? theme.colors.textMuted : theme.colors.text,
            fontFamily: theme.font,
            fontSize: '14px',
            cursor: playing ? 'not-allowed' : 'pointer',
          }}
        >
          {playing ? '...' : '>>'}
        </button>
        <button
          onClick={reset}
          style={{
            padding: '8px 12px',
            background: theme.colors.surface,
            border: 'none',
            borderRadius: '6px',
            color: theme.colors.text,
            fontFamily: theme.font,
            fontSize: '14px',
            cursor: 'pointer',
          }}
        >
          {'~'}
        </button>
      </div>

      {/* Math Details */}
      {step >= 1 && (
        <div style={{
          padding: '10px',
          background: theme.colors.surfaceAlt,
          borderRadius: '8px',
          marginBottom: '12px',
        }}>
          {step === 1 && (
            <div>
              <div style={{ fontSize: '11px', color: theme.colors.blue, marginBottom: '6px', fontWeight: '600' }}>
                Predictions = theta0 + theta1 * x
              </div>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: '6px' }}>
                {ex.X.map((row, i) => (
                  <div key={i} style={{
                    padding: '4px 8px',
                    background: theme.colors.surface,
                    borderRadius: '4px',
                    fontSize: '10px',
                  }}>
                    <span style={{ color: theme.colors.textMuted }}>x={row[1]}: </span>
                    <span style={{ color: theme.colors.blue }}>
                      {formatNum(theta[0] + theta[1] * row[1])}
                    </span>
                  </div>
                ))}
              </div>
            </div>
          )}

          {step === 2 && (
            <div>
              <div style={{ fontSize: '11px', color: theme.colors.negative, marginBottom: '6px', fontWeight: '600' }}>
                Errors = prediction - actual
              </div>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: '6px' }}>
                {errors.map((err, i) => (
                  <div key={i} style={{
                    padding: '4px 8px',
                    background: theme.colors.surface,
                    borderRadius: '4px',
                    fontSize: '10px',
                  }}>
                    <span style={{ color: theme.colors.negative }}>{formatNum(err)}</span>
                  </div>
                ))}
              </div>
              <div style={{ fontSize: '10px', color: theme.colors.textMuted, marginTop: '6px' }}>
                Loss = mean(errors squared) = {formatNum(currentLoss)}
              </div>
            </div>
          )}

          {step === 3 && (
            <div>
              <div style={{ fontSize: '11px', color: theme.colors.orange, marginBottom: '6px', fontWeight: '600' }}>
                Gradient points uphill (orange arrow)
              </div>
              <div style={{ fontSize: '10px', color: theme.colors.textSecondary, marginBottom: '6px' }}>
                We move opposite (green dashed) to decrease loss
              </div>
              <div style={{ display: 'flex', gap: '12px' }}>
                <div style={{ padding: '6px 10px', background: theme.colors.surface, borderRadius: '4px' }}>
                  <span style={{ color: theme.colors.textMuted, fontSize: '9px' }}>grad[0]: </span>
                  <span style={{ color: theme.colors.orange, fontSize: '12px' }}>{formatNum(gradient[0])}</span>
                </div>
                <div style={{ padding: '6px 10px', background: theme.colors.surface, borderRadius: '4px' }}>
                  <span style={{ color: theme.colors.textMuted, fontSize: '9px' }}>grad[1]: </span>
                  <span style={{ color: theme.colors.orange, fontSize: '12px' }}>{formatNum(gradient[1])}</span>
                </div>
              </div>
            </div>
          )}

          {(step === 4 || step === 5) && (
            <div>
              <div style={{ fontSize: '11px', color: theme.colors.green, marginBottom: '6px', fontWeight: '600' }}>
                theta = theta - alpha * gradient (iteration {iteration})
              </div>
              <div style={{ fontSize: '10px', color: theme.colors.textSecondary }}>
                alpha = {ex.alpha} (learning rate)
              </div>
              <div style={{ marginTop: '6px', fontSize: '10px' }}>
                <span style={{ color: theme.colors.textMuted }}>New position: </span>
                <span style={{ color: theme.colors.green }}>[{formatNum(theta[0])}, {formatNum(theta[1])}]</span>
                <span style={{ color: theme.colors.textMuted, marginLeft: '8px' }}>Loss: </span>
                <span style={{ color: theme.colors.yellow }}>{formatNum(currentLoss)}</span>
              </div>
            </div>
          )}

          {step === 6 && (
            <div>
              <div style={{ fontSize: '11px', color: theme.colors.primary, marginBottom: '6px', fontWeight: '600' }}>
                Running gradient descent...
              </div>
              <div style={{ fontSize: '10px', color: theme.colors.textSecondary }}>
                Watch the path trace through the loss landscape
              </div>
              {iteration >= 50 && (
                <div style={{ marginTop: '8px', fontSize: '11px', color: theme.colors.positive }}>
                  Converged at [{formatNum(theta[0])}, {formatNum(theta[1])}] with loss {formatNum(currentLoss)}
                </div>
              )}
            </div>
          )}
        </div>
      )}

      {/* Key Insight */}
      <div style={{
        padding: '10px 14px',
        background: theme.colors.surface,
        borderRadius: '8px',
        fontSize: '10px',
        color: theme.colors.textSecondary,
        textAlign: 'center',
      }}>
        <strong style={{ color: theme.colors.text }}>Key insight:</strong>{' '}
        The gradient always points uphill. By moving opposite to it, we descend into the valley where loss is minimized.
      </div>
    </div>
  );
}
